/**
 * sports-backtest.mjs - deterministic local sports betting ledger backtest
 *
 * Usage:
 *   node run.mjs pull sports-backtest --init-ledger
 *   node run.mjs pull sports-backtest --ledger scripts/.cache/sports/backtests/sample-ledger.csv
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'fs';
import { basename, dirname, join, relative, resolve } from 'path';
import { getPullsDir, getVaultRoot } from '../lib/config.mjs';
import { buildNote, buildTable, dateStampedFilename, today, writeNote } from '../lib/markdown.mjs';

const BACKTEST_CACHE_DIR = join(getVaultRoot(), 'scripts', '.cache', 'sports', 'backtests');
const SAMPLE_LEDGER_PATH = join(BACKTEST_CACHE_DIR, 'sample-ledger.csv');
const SAMPLE_LEDGER = `date,sport,league,event,market,selection,odds_decimal,model_probability,result,stake,closing_odds_decimal,notes
2026-04-01,baseball,MLB,Example A @ Example B,home_away,Example B,1.91,0.55,win,1,1.83,Sample positive edge
2026-04-02,basketball,NBA,Example C @ Example D,home_away,Example C,2.25,0.42,loss,1,2.10,Sample underdog edge
2026-04-03,ice-hockey,NHL,Example E @ Example F,home_away,Example F,1.80,0.54,push,1,1.78,Sample push
`;

export async function pull(flags = {}) {
  if (flags['init-ledger']) {
    mkdirSync(dirname(SAMPLE_LEDGER_PATH), { recursive: true });
    writeFileSync(SAMPLE_LEDGER_PATH, SAMPLE_LEDGER, 'utf8');
    console.log(`Sports backtest sample ledger: ${SAMPLE_LEDGER_PATH}`);
    return { filePath: SAMPLE_LEDGER_PATH, signals: [] };
  }

  if (!flags.ledger) {
    throw new Error('sports-backtest requires --ledger <csv>. Use --init-ledger to create a template.');
  }

  const ledgerPath = resolveLedgerPath(String(flags.ledger), flags);
  const rows = parseCsv(readFileSync(ledgerPath, 'utf8')).map(normalizeLedgerRow);
  const settled = rows.filter(row => row.result !== 'pending');
  if (rows.length === 0) throw new Error(`No rows found in ${ledgerPath}`);

  const summary = summarizeBacktest(rows, settled);
  const byMarket = groupSummaries(settled, row => `${row.sport} / ${row.league} / ${row.market}`);
  const topEdges = [...rows].sort((a, b) => b.edge - a.edge).slice(0, 20);
  const worstSettled = [...settled].sort((a, b) => a.pnl - b.pnl).slice(0, 10);

  const note = buildBacktestNote({ ledgerPath, rows, settled, summary, byMarket, topEdges, worstSettled });
  const label = `Sports_Backtest_${sanitizeFilename(basename(ledgerPath, '.csv'))}`;
  const filePath = join(getPullsDir(), 'Sports', dateStampedFilename(label));

  if (flags['dry-run']) {
    console.log(`[dry-run] Would write: ${filePath}`);
    console.log(JSON.stringify(summary, null, 2));
    return { filePath: null, summary, signals: [] };
  }

  writeNote(filePath, note);
  console.log(`Sports backtest wrote: ${filePath}`);
  return { filePath, summary, signals: summary.roi < 0 ? ['sports_backtest_negative_roi'] : [] };
}

function resolveLedgerPath(value, flags) {
  const resolved = resolve(getVaultRoot(), value);
  if (!resolved.startsWith(getVaultRoot()) && !flags['allow-outside-vault']) {
    throw new Error('Ledger path must be inside the vault unless --allow-outside-vault is set.');
  }
  if (!existsSync(resolved)) throw new Error(`Ledger not found: ${resolved}`);
  return resolved;
}

function normalizeLedgerRow(row) {
  const oddsDecimal = parseOdds(row.odds_decimal || row.odds || row.decimal_odds, row.odds_american || row.american_odds);
  const probability = parseProbability(row.model_probability || row.probability || row.p);
  const stake = parseOptionalNumber(row.stake, 1);
  const closingOdds = row.closing_odds_decimal || row.closing_odds
    ? parseOdds(row.closing_odds_decimal || row.closing_odds, row.closing_odds_american)
    : null;
  const result = normalizeResult(row.result || row.outcome);

  const impliedProbability = 1 / oddsDecimal;
  const edge = probability - impliedProbability;
  const expectedValue = stake * ((probability * (oddsDecimal - 1)) - (1 - probability));
  const pnl = result === 'win' ? stake * (oddsDecimal - 1)
    : result === 'loss' ? -stake
      : 0;
  const clv = closingOdds ? ((oddsDecimal / closingOdds) - 1) * 100 : null;

  return {
    date: requireText(row.date, 'date'),
    sport: row.sport || '',
    league: row.league || '',
    event: requireText(row.event, 'event'),
    market: requireText(row.market, 'market'),
    selection: requireText(row.selection, 'selection'),
    oddsDecimal,
    probability,
    impliedProbability,
    edge,
    expectedValue,
    result,
    stake,
    pnl,
    closingOdds,
    clv,
    notes: row.notes || '',
  };
}

function summarizeBacktest(rows, settled) {
  const totalStake = sum(settled, row => row.stake);
  const totalPnl = sum(settled, row => row.pnl);
  const wins = settled.filter(row => row.result === 'win').length;
  const losses = settled.filter(row => row.result === 'loss').length;
  const pushes = settled.filter(row => row.result === 'push').length;
  const avgEdge = average(rows, row => row.edge);
  const avgEv = average(rows, row => row.expectedValue);
  const avgClv = average(settled.filter(row => row.clv !== null), row => row.clv);

  return {
    rows: rows.length,
    settled: settled.length,
    pending: rows.length - settled.length,
    wins,
    losses,
    pushes,
    totalStake,
    totalPnl,
    roi: totalStake ? (totalPnl / totalStake) * 100 : 0,
    hitRate: wins + losses ? (wins / (wins + losses)) * 100 : 0,
    averageEdge: avgEdge * 100,
    averageExpectedValue: avgEv,
    averageClv: avgClv,
  };
}

function groupSummaries(rows, keyFn) {
  const groups = new Map();
  for (const row of rows) {
    const key = keyFn(row);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(row);
  }

  return [...groups.entries()]
    .map(([key, groupRows]) => ({ key, ...summarizeBacktest(groupRows, groupRows) }))
    .sort((a, b) => b.totalPnl - a.totalPnl);
}

function buildBacktestNote({ ledgerPath, rows, settled, summary, byMarket, topEdges, worstSettled }) {
  return buildNote({
    frontmatter: {
      title: `Sports Backtest - ${basename(ledgerPath)}`,
      source: 'Local sports betting ledger',
      date_pulled: today(),
      domain: 'sports',
      data_type: 'sports_backtest',
      frequency: 'on-demand',
      signal_status: summary.roi < 0 ? 'watch' : 'clear',
      signals: summary.roi < 0 ? ['sports_backtest_negative_roi'] : [],
      tags: ['sports', 'backtest', 'betting-ledger'],
    },
    sections: [
      {
        heading: 'Executive Summary',
        content: [
          `Ledger: ${relative(getVaultRoot(), ledgerPath)}`,
          `Rows: ${summary.rows}`,
          `Settled: ${summary.settled}`,
          `Pending: ${summary.pending}`,
          `P/L: ${formatMoney(summary.totalPnl)} on ${formatMoney(summary.totalStake)} staked`,
          `ROI: ${formatPercent(summary.roi)}`,
          `Hit rate: ${formatPercent(summary.hitRate)}`,
          `Average model edge: ${formatPercent(summary.averageEdge)}`,
          `Average expected value per bet: ${formatMoney(summary.averageExpectedValue)}`,
          `Average CLV: ${summary.averageClv === null ? 'N/A' : formatPercent(summary.averageClv)}`,
        ].join('\n'),
      },
      {
        heading: 'By Sport / League / Market',
        content: byMarket.length
          ? buildTable(['Bucket', 'Bets', 'P/L', 'ROI', 'Hit Rate', 'Avg Edge'], byMarket.map(row => [
            row.key,
            row.settled,
            formatMoney(row.totalPnl),
            formatPercent(row.roi),
            formatPercent(row.hitRate),
            formatPercent(row.averageEdge),
          ]))
          : 'No settled rows available.',
      },
      {
        heading: 'Top Model Edges',
        content: buildTable(['Date', 'Event', 'Market', 'Selection', 'Odds', 'Model P', 'Edge', 'EV', 'Result', 'P/L'], topEdges.map(row => [
          row.date,
          row.event,
          row.market,
          row.selection,
          row.oddsDecimal.toFixed(3),
          formatPercent(row.probability * 100),
          formatPercent(row.edge * 100),
          formatMoney(row.expectedValue),
          row.result,
          row.result === 'pending' ? 'Pending' : formatMoney(row.pnl),
        ])),
      },
      {
        heading: 'Worst Settled Bets',
        content: worstSettled.length
          ? buildTable(['Date', 'Event', 'Selection', 'Odds', 'Result', 'P/L', 'CLV', 'Notes'], worstSettled.map(row => [
            row.date,
            row.event,
            row.selection,
            row.oddsDecimal.toFixed(3),
            row.result,
            formatMoney(row.pnl),
            row.clv === null ? 'N/A' : formatPercent(row.clv),
            row.notes,
          ]))
          : 'No settled losses yet.',
      },
      {
        heading: 'Ledger Contract',
        content: [
          'Required columns: `date`, `event`, `market`, `selection`, `model_probability`, `result`, plus `odds_decimal` or `odds_american`.',
          'Optional columns: `sport`, `league`, `stake`, `closing_odds_decimal`, `closing_odds_american`, `notes`.',
          'Result values: `win`, `loss`, `push`, or `pending`.',
          'This backtester does not load Python config files, model pickles, or third-party serialized objects.',
        ].join('\n'),
      },
    ],
  });
}

function parseCsv(raw) {
  const rows = [];
  const records = parseCsvRecords(raw);
  if (records.length === 0) return rows;
  const headers = records[0].map(header => header.trim());
  for (const record of records.slice(1)) {
    if (record.every(cell => cell.trim() === '')) continue;
    const row = {};
    headers.forEach((header, index) => {
      row[header] = record[index] ?? '';
    });
    rows.push(row);
  }
  return rows;
}

function parseCsvRecords(raw) {
  const records = [];
  let record = [];
  let field = '';
  let inQuotes = false;

  for (let i = 0; i < raw.length; i++) {
    const char = raw[i];
    const next = raw[i + 1];

    if (char === '"') {
      if (inQuotes && next === '"') {
        field += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (char === ',' && !inQuotes) {
      record.push(field);
      field = '';
      continue;
    }

    if ((char === '\n' || char === '\r') && !inQuotes) {
      if (char === '\r' && next === '\n') i++;
      record.push(field);
      records.push(record);
      record = [];
      field = '';
      continue;
    }

    field += char;
  }

  if (field.length > 0 || record.length > 0) {
    record.push(field);
    records.push(record);
  }

  return records;
}

function parseOdds(decimalValue, americanValue) {
  if (decimalValue !== undefined && decimalValue !== '') {
    const parsed = Number(decimalValue);
    if (!Number.isFinite(parsed) || parsed <= 1) throw new Error(`Invalid decimal odds: ${decimalValue}`);
    return parsed;
  }

  const american = Number(americanValue);
  if (!Number.isFinite(american) || american === 0) throw new Error(`Invalid American odds: ${americanValue}`);
  return american > 0 ? 1 + (american / 100) : 1 + (100 / Math.abs(american));
}

function parseProbability(value) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) throw new Error(`Invalid model probability: ${value}`);
  const probability = parsed > 1 ? parsed / 100 : parsed;
  if (probability <= 0 || probability >= 1) throw new Error(`Model probability must be between 0 and 1: ${value}`);
  return probability;
}

function parseOptionalNumber(value, fallback) {
  if (value === undefined || value === '') return fallback;
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) throw new Error(`Invalid number: ${value}`);
  return parsed;
}

function normalizeResult(value) {
  const normalized = String(value || 'pending').trim().toLowerCase();
  if (['w', 'won', 'win', '1', 'true'].includes(normalized)) return 'win';
  if (['l', 'lost', 'loss', '0', 'false'].includes(normalized)) return 'loss';
  if (['p', 'push', 'void', 'refund'].includes(normalized)) return 'push';
  if (['pending', 'open', ''].includes(normalized)) return 'pending';
  throw new Error(`Invalid result: ${value}`);
}

function requireText(value, field) {
  const text = String(value || '').trim();
  if (!text) throw new Error(`Ledger row missing required field: ${field}`);
  return text;
}

function sum(rows, fn) {
  return rows.reduce((total, row) => total + fn(row), 0);
}

function average(rows, fn) {
  return rows.length ? sum(rows, fn) / rows.length : null;
}

function formatMoney(value) {
  if (value === null || value === undefined || Number.isNaN(value)) return 'N/A';
  return value.toFixed(2);
}

function formatPercent(value) {
  if (value === null || value === undefined || Number.isNaN(value)) return 'N/A';
  return `${value.toFixed(2)}%`;
}

function sanitizeFilename(value) {
  return String(value)
    .replace(/[<>:"/\\|?*]+/g, '_')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '');
}

/**
 * sports-odds.mjs - optional OddsHarvester wrapper for sports odds ingestion
 *
 * Usage:
 *   node run.mjs pull sports-odds --date 2026-04-28 --dry-run
 *   node run.mjs pull sports-odds --from 2026-04-27 --to 2026-04-28 --sports baseball,basketball,ice-hockey
 *   node run.mjs pull sports-odds --sport football --league england-premier-league --market 1x2
 *
 * Requires: pipx install oddsharvester, or provide --executable <path>
 */

import { spawnSync } from 'child_process';
import { existsSync, mkdirSync, readFileSync } from 'fs';
import { dirname, join, relative, resolve } from 'path';
import { getPullsDir, getVaultRoot } from '../lib/config.mjs';
import { buildNote, buildTable, dateStampedFilename, today, writeNote } from '../lib/markdown.mjs';

const CACHE_DIR = join(getVaultRoot(), 'scripts', '.cache', 'sports', 'odds');
const DEFAULT_UPCOMING_SPORTS = Object.freeze(['baseball', 'basketball', 'ice-hockey']);
const SPORT_DEFAULTS = Object.freeze({
  baseball: Object.freeze({ league: 'mlb', market: 'home_away' }),
  basketball: Object.freeze({ league: 'nba', market: 'home_away' }),
  'ice-hockey': Object.freeze({ league: 'nhl', market: 'home_away' }),
  'american-football': Object.freeze({ league: 'nfl', market: 'home_away' }),
  football: Object.freeze({ league: '', market: '1x2' }),
  tennis: Object.freeze({ league: '', market: 'match_winner' }),
});

export async function pull(flags = {}) {
  const mode = String(flags.mode || (flags.historic ? 'historic' : 'upcoming')).toLowerCase();
  if (!['upcoming', 'historic'].includes(mode)) {
    throw new Error('--mode must be "upcoming" or "historic"');
  }

  const executable = String(flags.executable || process.env.ODDSHARVESTER_BIN || 'oddsharvester');
  const dryRun = Boolean(flags['dry-run']);
  const format = validateFormat(String(flags.format || 'json'));
  const jobs = buildJobs(flags, mode, format);

  if (!dryRun) {
    assertOddsharvesterAvailable(executable);
    mkdirSync(CACHE_DIR, { recursive: true });
  }

  console.log(`Sports odds: ${mode} ${jobs.length} OddsHarvester job(s)`);
  const results = [];
  for (const job of jobs) {
    const command = buildCommand(executable, job, flags, mode, format);
    console.log(`  ${formatCommand(command)}`);

    if (dryRun) {
      results.push({ ...job, command, status: 'dry-run', exitCode: null, outputFile: outputFileFor(job, format), records: null, error: '' });
      continue;
    }

    const result = runCommand(command, flags);
    const outputFile = outputFileFor(job, format);
    const records = existsSync(outputFile) ? countRecords(outputFile, format) : null;
    results.push({
      ...job,
      command,
      status: result.status === 0 ? 'ok' : 'error',
      exitCode: result.status,
      outputFile,
      records,
      error: result.status === 0 ? '' : summarizeProcessError(result),
    });
  }

  if (dryRun) {
    console.log('  [dry-run] No scraper commands executed and no note written.');
    return { filePath: null, results, signals: [] };
  }

  const note = buildOddsNote(mode, results, flags, format);
  const label = mode === 'historic'
    ? `Sports_Odds_Harvest_${mode}_${sanitizeFilename(flags.season || 'current')}`
    : `Sports_Odds_Harvest_${mode}_${results[0]?.eventDate || today()}`;
  const filePath = join(getPullsDir(), 'Sports', dateStampedFilename(label));
  writeNote(filePath, note);
  console.log(`  Wrote: ${filePath}`);

  return {
    filePath,
    results,
    signals: results.filter(result => result.status === 'error').map(result => `sports_odds_error:${result.sport}`),
  };
}

function buildJobs(flags, mode, format) {
  const sports = resolveSports(flags);
  const marketsBySport = resolveMappedOption(flags.market || flags.markets);
  const leaguesBySport = resolveMappedOption(flags.league || flags.leagues);
  const dates = mode === 'upcoming' ? resolveDates(flags) : [null];

  if (mode === 'historic' && !flags.season) {
    throw new Error('Historic odds pulls require --season <YYYY|YYYY-YYYY|current>');
  }

  const jobs = [];
  for (const date of dates) {
    for (const sport of sports) {
      const defaults = SPORT_DEFAULTS[sport] || { league: '', market: 'home_away' };
      const league = leaguesBySport[sport] ?? leaguesBySport.default ?? defaults.league;
      const market = marketsBySport[sport] ?? marketsBySport.default ?? defaults.market;
      const slugParts = [mode, date || flags.season || 'current', sport, league || 'all', market].map(sanitizeFilename);
      jobs.push({
        mode,
        eventDate: date,
        sport,
        league,
        market,
        season: flags.season ? String(flags.season) : '',
        outputStem: join(CACHE_DIR, date || flags.season || 'historic', slugParts.join('_')),
        outputFormat: format,
      });
    }
  }
  return jobs;
}

function buildCommand(executable, job, flags, mode, format) {
  const args = [executable, mode, '--sport', job.sport, '--market', job.market, '--storage', 'local', '--format', format, '--output', job.outputStem];

  if (mode === 'upcoming') {
    args.push('--date', job.eventDate.replaceAll('-', ''));
  } else {
    args.push('--season', job.season);
    if (flags['max-pages']) args.push('--max-pages', String(flags['max-pages']));
  }

  if (job.league && !flags['no-league']) args.push('--league', job.league);
  if (flags['match-link']) args.push('--match-link', String(flags['match-link']));
  if (truthyFlag(flags.headless, true)) args.push('--headless');
  if (flags['preview-only']) args.push('--preview-only');
  if (flags['odds-history']) args.push('--odds-history');
  if (flags['target-bookmaker']) args.push('--target-bookmaker', String(flags['target-bookmaker']));
  if (flags['bookies-filter']) args.push('--bookies-filter', String(flags['bookies-filter']));
  if (flags.period) args.push('--period', String(flags.period));

  args.push('--concurrency', String(parsePositiveInt(flags.concurrency, 1, '--concurrency')));
  args.push('--request-delay', String(parsePositiveNumber(flags['request-delay'], 3, '--request-delay')));

  return args;
}

function runCommand(command, flags) {
  const [executable, ...args] = command;
  const timeoutMinutes = parsePositiveNumber(flags['timeout-min'], 15, '--timeout-min');
  return spawnSync(executable, args, {
    cwd: getVaultRoot(),
    encoding: 'utf8',
    timeout: timeoutMinutes * 60 * 1000,
    env: {
      ...process.env,
      OH_STORAGE: 'local',
      OH_HEADLESS: 'true',
      OH_CONCURRENCY: String(parsePositiveInt(flags.concurrency, 1, '--concurrency')),
      OH_REQUEST_DELAY: String(parsePositiveNumber(flags['request-delay'], 3, '--request-delay')),
    },
  });
}

function assertOddsharvesterAvailable(executable) {
  const result = spawnSync(executable, ['--help'], { encoding: 'utf8', timeout: 30_000 });
  if (result.error) {
    throw new Error(`OddsHarvester executable not available: ${result.error.message}. Install with "pipx install oddsharvester" or pass --executable <path>.`);
  }
}

function buildOddsNote(mode, results, flags, format) {
  const errors = results.filter(result => result.status === 'error');
  const rows = results.map(result => [
    result.eventDate || result.season || '',
    result.sport,
    result.league || 'all',
    result.market,
    result.status,
    result.records ?? 'N/A',
    result.outputFile ? relative(getVaultRoot(), result.outputFile) : '',
    result.error || '',
  ]);

  const commandRows = results.map(result => [
    result.sport,
    result.league || 'all',
    formatCommand(result.command),
  ]);

  return buildNote({
    frontmatter: {
      title: `Sports Odds Harvest - ${mode}`,
      source: 'OddsHarvester / OddsPortal',
      date_pulled: today(),
      domain: 'sports',
      data_type: mode === 'historic' ? 'historical_odds' : 'upcoming_odds',
      frequency: 'on-demand',
      signal_status: errors.length > 0 ? 'watch' : 'clear',
      signals: errors.map(result => `sports_odds_error:${result.sport}`),
      tags: ['sports', 'odds', 'oddsharvester', 'backtesting-input'],
    },
    sections: [
      {
        heading: 'Executive Summary',
        content: [
          `Mode: ${mode}`,
          `Jobs completed: ${results.length - errors.length}/${results.length}`,
          `Output format: ${format}`,
          `Local cache: ${relative(getVaultRoot(), CACHE_DIR)}`,
          '',
          'Use this as an odds-history or line-context input for sports-backtest. The daily ESPN slate remains the schedule baseline.',
        ].join('\n'),
      },
      {
        heading: 'Harvest Results',
        content: buildTable(['Date/Season', 'Sport', 'League', 'Market', 'Status', 'Records', 'Output File', 'Error'], rows),
      },
      {
        heading: 'Safety Controls',
        content: [
          '- Remote/S3 storage is not exposed by this wrapper; all jobs force `--storage local`.',
          '- Default concurrency is 1 and default request delay is 3 seconds.',
          '- Browser mode is headless by default.',
          '- Scraper output stays in `scripts/.cache/sports/odds/`; the vault note stores only a source log and file pointers.',
          '- Check OddsPortal terms and local law before running live scraping at scale.',
        ].join('\n'),
      },
      {
        heading: 'Command Log',
        content: buildTable(['Sport', 'League', 'Command'], commandRows),
      },
    ],
  });
}

function resolveSports(flags) {
  const raw = flags.sports || flags.sport;
  if (!raw) return DEFAULT_UPCOMING_SPORTS;
  return String(raw).split(',').map(item => item.trim().toLowerCase()).filter(Boolean);
}

function resolveMappedOption(raw) {
  if (!raw) return {};
  const text = String(raw);
  const result = {};
  for (const part of text.split(',').map(item => item.trim()).filter(Boolean)) {
    const [key, value] = part.includes(':') ? part.split(':', 2) : ['default', part];
    result[key.trim().toLowerCase()] = value.trim();
  }
  return result;
}

function resolveDates(flags) {
  if (flags.date) return [validateDate(String(flags.date))];

  const from = flags.from ? validateDate(String(flags.from)) : today();
  if (flags.to) return dateRange(from, validateDate(String(flags.to)));

  const days = parsePositiveInt(flags.days, 1, '--days');
  if (days > 7) throw new Error('--days is capped at 7 for sports-odds');

  const dates = [];
  let cursor = parseDate(from);
  for (let i = 0; i < days; i++) {
    dates.push(formatDate(cursor));
    cursor = addDays(cursor, 1);
  }
  return dates;
}

function validateDate(value) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(value)) throw new Error(`Invalid date "${value}". Use YYYY-MM-DD.`);
  const parsed = parseDate(value);
  if (formatDate(parsed) !== value) throw new Error(`Invalid date "${value}". Use a real calendar date.`);
  return value;
}

function dateRange(from, to) {
  const start = parseDate(from);
  const end = parseDate(to);
  if (end < start) throw new Error('--to must be on or after --from');

  const dates = [];
  let cursor = start;
  while (cursor <= end) {
    dates.push(formatDate(cursor));
    cursor = addDays(cursor, 1);
    if (dates.length > 7) throw new Error('sports-odds date ranges are capped at 7 days');
  }
  return dates;
}

function parseDate(value) {
  return new Date(`${value}T00:00:00Z`);
}

function addDays(date, days) {
  const next = new Date(date.getTime());
  next.setUTCDate(next.getUTCDate() + days);
  return next;
}

function formatDate(date) {
  return date.toISOString().slice(0, 10);
}

function outputFileFor(job, format) {
  return `${job.outputStem}.${format}`;
}

function countRecords(filePath, format) {
  const raw = readFileSync(filePath, 'utf8');
  if (format === 'json') {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed.length : 1;
  }
  const lines = raw.split(/\r?\n/).filter(Boolean);
  return Math.max(0, lines.length - 1);
}

function summarizeProcessError(result) {
  if (result.error) return result.error.message;
  return [result.stderr, result.stdout].filter(Boolean).join(' ').slice(0, 300);
}

function validateFormat(format) {
  if (!['json', 'csv'].includes(format)) throw new Error('--format must be json or csv');
  return format;
}

function parsePositiveInt(value, fallback, label) {
  if (value === undefined || value === null || value === true) return fallback;
  const parsed = parseInt(String(value), 10);
  if (!Number.isInteger(parsed) || parsed <= 0) throw new Error(`${label} must be a positive integer`);
  return parsed;
}

function parsePositiveNumber(value, fallback, label) {
  if (value === undefined || value === null || value === true) return fallback;
  const parsed = Number(String(value));
  if (!Number.isFinite(parsed) || parsed <= 0) throw new Error(`${label} must be a positive number`);
  return parsed;
}

function truthyFlag(value, fallback) {
  if (value === undefined || value === null) return fallback;
  return !['false', '0', 'no'].includes(String(value).toLowerCase());
}

function formatCommand(command) {
  return command.map(part => quoteArg(part)).join(' ');
}

function quoteArg(value) {
  const text = String(value);
  return /[\s"'`]/.test(text) ? `"${text.replace(/"/g, '\\"')}"` : text;
}

function sanitizeFilename(value) {
  return String(value || 'all')
    .replace(/[<>:"/\\|?*]+/g, '_')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '');
}

